mapper.select:
SELECT a.award_id, a.project_id, p.project_name, a.lot_id, l.lot_code, l.lot_name, a.evaluation_id, a.status, a.winning_submission_id, a.winner_enterprise_id, a.winner_name_snapshot, a.winner_credit_code, a.award_amount, a.confirm_user_id, a.confirm_time, a.public_notice_time, a.rollback_reason, a.remark, a.version, a.create_time, a.update_time FROM t_bid_award a INNER JOIN t_bid_project p ON p.project_id = a.project_id INNER JOIN t_bid_lot l ON l.lot_id = a.lot_id
a.deleted_flag = #{queryForm.deletedFlag} AND p.deleted_flag = 0 AND l.deleted_flag = 0
AND ( p.project_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_name LIKE CONCAT('%', #{queryForm.keyword}, '%') OR l.lot_code LIKE CONCAT('%', #{queryForm.keyword}, '%') OR a.winner_name_snapshot LIKE CONCAT('%', #{queryForm.keyword}, '%') OR a.winner_credit_code LIKE CONCAT('%', #{queryForm.keyword}, '%') )
AND a.project_id = #{queryForm.projectId}
AND a.lot_id = #{queryForm.lotId}
AND a.evaluation_id = #{queryForm.evaluationId}
AND a.status = #{queryForm.status}
ORDER BY a.create_time DESC, a.award_id DESC
